class Solution {
public:
    bool isSymmetric(TreeNode* root) {
        function<bool(TreeNode*,TreeNode*)> mir = [&](TreeNode* a, TreeNode* b) {
            if (!a && !b) return true;
            if (!a || !b || a->val != b->val) return false;
            return mir(a->left, b->right) && mir(a->right, b->left);
        };
        return !root || mir(root->left, root->right);
    }
};
